33	pub struct App {
34	    selected: usize,
35	    source: String,
36	    output: String,
37	    status: String,
38	    error: bool,
39	    session: Option<Session>,
40	    running: bool,
41	    max_instrs: u64,
42	    started_at: f64,
43	    elapsed_ms: f64,
44	    budget_exhausted: bool,
45	    input_line: String,
46	    awaiting_input: bool,
47	    output_ref: NodeRef,
48	    input_ref: NodeRef,
49	}
