51	impl App {
52	    fn load_demo(&mut self, idx: usize) {
53	        if let Some(demo) = DEMOS.get(idx) {
54	            self.selected = idx;
55	            self.source = demo.source.to_string();
56	            self.output.clear();
57	            self.status = "idle".into();
58	            self.error = false;
59	            self.session = None;
60	            self.running = false;
61	            self.budget_exhausted = false;
62	            self.elapsed_ms = 0.0;
63	            self.input_line.clear();
64	            self.awaiting_input = false;
65	        }
66	    }
67	
68	    fn start_run(&mut self, ctx: &Context<Self>) {
69	        let interactive = DEMOS
70	            .get(self.selected)
71	            .map(|d| d.interactive)
72	            .unwrap_or(false);
73	        self.session = Some(if interactive {
74	            Session::new_interactive(&self.source)
75	        } else {
76	            Session::new(&self.source)
77	        });
78	        self.input_line.clear();
79	        self.awaiting_input = false;
80	        self.running = true;
81	        self.error = false;
82	        self.budget_exhausted = false;
83	        self.output.clear();
84	        self.started_at = now_ms();
85	        self.elapsed_ms = 0.0;
86	        self.status = "running...".into();
87	        self.schedule_tick(ctx);
88	    }
89	
90	    fn schedule_tick(&self, ctx: &Context<Self>) {
91	        let link = ctx.link().clone();
92	        Timeout::new(TICK_DELAY_MS, move || link.send_message(Msg::Tick)).forget();
93	    }
94	
95	    fn finish(&mut self, status: String, error: bool) {
96	        self.running = false;
97	        self.status = status;
98	        self.error = error;
99	        self.elapsed_ms = now_ms() - self.started_at;
100	        if let Some(s) = &self.session {
101	            let raw = s.output();
102	            self.output = raw;
103	        }
104	    }
105	}
106	
107	impl Component for App {
108	    type Message = Msg;
109	    type Properties = ();
110	
111	    fn create(_ctx: &Context<Self>) -> Self {
112	        let idx = default_demo_index();
113	        let demo = &DEMOS[idx];
114	        Self {
115	            selected: idx,
116	            source: demo.source.to_string(),
117	            output: String::new(),
118	            status: "idle".into(),
119	            error: false,
120	            session: None,
121	            running: false,
122	            max_instrs: DEFAULT_MAX_INSTRS,
123	            started_at: 0.0,
124	            elapsed_ms: 0.0,
125	            budget_exhausted: false,
126	            input_line: String::new(),
127	            awaiting_input: false,
128	            output_ref: NodeRef::default(),
129	            input_ref: NodeRef::default(),
130	        }
131	    }
132	
133	    fn rendered(&mut self, _ctx: &Context<Self>, _first_render: bool) {
134	        if let Some(el) = self.output_ref.cast::<Element>() {
135	            el.set_scroll_top(el.scroll_height());
136	        }
137	        if self.awaiting_input
138	            && let Some(el) = self.input_ref.cast::<HtmlInputElement>()
139	        {
140	            let _ = el.focus();
141	        }
142	    }
143	
144	    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
145	        match msg {
146	            Msg::SelectDemo(i) => {
147	                self.load_demo(i);
148	                self.max_instrs = DEFAULT_MAX_INSTRS;
149	                true
150	            }
151	            Msg::SourceChanged(v) => {
152	                self.source = v;
153	                false
154	            }
155	            Msg::Run => {
156	                self.max_instrs = DEFAULT_MAX_INSTRS;
157	                self.start_run(ctx);
158	                true
159	            }
160	            Msg::IncreaseBudget => {
161	                self.max_instrs = self.max_instrs.saturating_mul(4);
162	                self.start_run(ctx);
163	                true
164	            }
165	            Msg::Stop => {
166	                if self.running {
167	                    self.finish("stopped".into(), false);
168	                }
169	                true
170	            }
171	            Msg::Reset => {
172	                let idx = self.selected;
173	                self.running = false;
174	                self.session = None;
175	                self.load_demo(idx);
176	                self.max_instrs = DEFAULT_MAX_INSTRS;
177	                true
178	            }
179	            Msg::Clear => {
180	                self.output.clear();
181	                if !self.running {
182	                    self.status = "idle".into();
183	                    self.error = false;
184	                    self.budget_exhausted = false;
185	                }
186	                true
187	            }
188	            Msg::Tick => {
189	                if !self.running {
190	                    return false;
191	                }
192	                let Some(session) = self.session.as_mut() else {
193	                    self.running = false;
194	                    return true;
195	                };
196	                let interactive = DEMOS
197	                    .get(self.selected)
198	                    .map(|d| d.interactive)
199	                    .unwrap_or(false);
200	                if !interactive {
201	                    let remaining = self.max_instrs.saturating_sub(session.instructions());
202	                    if remaining == 0 {
203	                        self.budget_exhausted = true;
204	                        let instrs = session.instructions();
205	                        self.finish(format!("halted (budget) -- {} instrs", instrs), true);
206	                        return true;
207	                    }
208	                }
209	                let result = session.tick();
210	                if session.is_awaiting_input() {
211	                    self.awaiting_input = true;
212	                    self.output = session.output();
213	                    self.elapsed_ms = now_ms() - self.started_at;
214	                    self.status = format!(
215	                        "awaiting input ({} instrs, {:.0} ms)",
216	                        session.instructions(),
217	                        self.elapsed_ms
218	                    );
219	                    return true;
220	                }
221	                if result.done {
222	                    let instrs = session.instructions();
223	                    let reason = session.stop_reason();
224	                    let halted = session.is_halted();
225	                    self.finish(
226	                        format!(
227	                            "{} ({} instrs, {:.0} ms)",
228	                            reason,
229	                            instrs,
230	                            now_ms() - self.started_at
231	                        ),
232	                        !halted,
233	                    );
234	                } else {
235	                    self.output = session.output();
236	                    self.elapsed_ms = now_ms() - self.started_at;
237	                    self.status = format!(
238	                        "running... {} instrs, {:.0} ms",
239	                        session.instructions(),
240	                        self.elapsed_ms
241	                    );
242	                    self.schedule_tick(ctx);
243	                }
244	                true
245	            }
246	            Msg::InputChanged(v) => {
247	                self.input_line = v;
248	                false
249	            }
250	            Msg::InputSubmit => {
251	                if !self.awaiting_input {
252	                    return false;
253	                }
254	                let line = std::mem::take(&mut self.input_line);
255	                if let Some(session) = self.session.as_mut() {
256	                    session.feed_input(&line);
257	                }
258	                self.awaiting_input = false;
259	                self.status = "running...".into();
260	                self.schedule_tick(ctx);
261	                true
262	            }
263	            Msg::KeyDown(e) => {
264	                if e.key() == "Enter" && (e.ctrl_key() || e.meta_key()) {
265	                    e.prevent_default();
266	                    ctx.link().send_message(Msg::Run);
267	                } else if e.key() == "Escape" && self.running {
268	                    e.prevent_default();
269	                    ctx.link().send_message(Msg::Stop);
270	                }
271	                false
272	            }
273	        }
274	    }
