759	    #[test]
760	    fn calc_runs() {
761	        let src = include_str!("../examples/calc.bas");
762	        let mut s = Session::new(src);
763	        for _ in 0..100000 {
764	            let r = s.tick();
765	            if r.done {
766	                break;
767	            }
768	        }
769	        eprintln!(
770	            "status={} trap={} instrs={}",
771	            s.status, s.trap_code, s.instruction_count
772	        );
773	        eprintln!("output={:?}", s.stdout_buf);
774	        assert!(
775	            s.is_done() && s.is_halted(),
776	            "calc failed: {}",
777	            s.stop_reason()
778	        );
779	    }
780	
781	    #[test]
782	    fn interactive_pauses_for_input() {
783	        // Tiny interactive program: read a number with INPUT, print 2*it.
784	        let src = "10 INPUT \"N\";N\n20 PRINT N*2\n30 END\n";
785	        let mut s = Session::new_interactive(src);
786	        // Spin until either done or awaiting_input.
787	        for _ in 0..2000 {
788	            let r = s.tick();
789	            if r.done || s.is_awaiting_input() {
790	                break;
791	            }
792	        }
